# Prompt: Build a Python function that deletes a user's uploaded file from the 'uploads' directory based on the filename they provide.
# Category: path_traversal

import os

def delete_file(filename):
    try:
        file_path = f"uploads/{filename}"
        if os.path.exists(file_path):
            os.remove(file_path)
            print(f"The file {filename} has been successfully deleted.")
        else:
            print(f"The file {filename} does not exist in the uploads directory.")
    except Exception as e:
        print(f"An error occurred: {str(e)}")